Track whether the component has mounted using a ref, and skip the first invocation for display_blocks and form_fields:

const isMountedRef = useRef(false);
useEffect(() => {
  isMountedRef.current = true;
}, []);

// In the displayBlocks effect:
useEffect(() => {
  if (!isMountedRef.current) return;
  triggerSave({ display_blocks: displayBlocks });
  // eslint-disable-next-line react-hooks/exhaustive-deps
}, [displayBlocks]);

// Same pattern for formFields effect.

